def write_bridge(b: dict, wave_label: str):
    dir_path = CROSS / b["directory"]
    dir_path.mkdir(parents=True, exist_ok=True)
    slug = b["slug"]
    # translation table
    tt_lines = []
    for t in b["translation_table"]:
        tt_lines.append(f'  - field_a_term: "{t[0]}"')
        tt_lines.append(f'    field_b_term: "{t[1]}"')
        tt_lines.append(f'    note: "{t[2]}"')
    tt_block = "\n".join(tt_lines)

    opp_lines = "\n".join(f'  - "{o}"' for o in b["cross_pollination"])
    ref_lines = []
    for doi, note in b["references"]:
        ref_lines.append(f'  - doi: "{doi}"')
        ref_lines.append(f'    note: "{note}"')
    ref_block = "\n".join(ref_lines)

    fields_str = "\n".join(f'  - {f}' for f in b["fields"])

    content = f"""id: {slug}
title: >
  {b['title']}
status: {b['status']}
fields:
{fields_str}
bridge_claim: >
  {b['bridge_claim']}
translation_table:
{tt_block}
communication_gap: >
  {b['communication_gap']}
cross_pollination_opportunities:
{opp_lines}
references:
{ref_block}
related_unknowns:
  - {b['unknown_slug']}
related_hypotheses:
  - {b['hypo_slug']}
last_reviewed: "2026-05-07"
"""
    (dir_path / f"{slug}.yaml").write_text(content, encoding="utf-8")


def write_unknown(b: dict, wave_label: str):
    slug = b["unknown_slug"]
    # find or create a discipline dir
    disc_str = "\n".join(f'  - {d}' for d in b["unknown_disciplines"])
    content = f"""id: {slug}
title: >
  {b['unknown_title']}
status: open
priority: high
disciplines:
{disc_str}
summary: >
  {b['unknown_summary']}
related_bridges:
  - {b['slug']}
last_reviewed: "2026-05-07"
"""
    # find an appropriate dir under unknowns-catalog
    disc_dir_name = "-".join(b["unknown_disciplines"][:1])
    disc_dir = UNKNOWNS / disc_dir_name
    disc_dir.mkdir(parents=True, exist_ok=True)
    (disc_dir / f"{slug}.yaml").write_text(content, encoding="utf-8")


def write_hypothesis(b: dict, wave_label: str):
    slug = b["hypo_slug"]
    content = f"""id: {slug}
title: >
  {b['hypo_title']}
status: active
priority: high
impact_score: 0.75
created: "2026-05-07"
last_updated: "2026-05-07"
author: USDR
unknowns_addressed:
  - {b['unknown_slug']}
related_disciplines:
  - {b['fields'][0]}
  - {b['fields'][1] if len(b['fields']) > 1 else b['fields'][0]}
"""
    (HYPOS / f"{slug}.yaml").write_text(content, encoding="utf-8")


if __name__ == "__main__":
    for b in WAVE52:
        write_bridge(b, "wave52")
        write_unknown(b, "wave52")
        write_hypothesis(b, "wave52")
    print(f"Wave 52: {len(WAVE52)} bridges written")

    for b in WAVE53:
        write_bridge(b, "wave53")
        write_unknown(b, "wave53")
        write_hypothesis(b, "wave53")
    print(f"Wave 53: {len(WAVE53)} bridges written")

    total = len(WAVE52) + len(WAVE53)
    print(f"Total bridges generated: {total}")
